// Pull both `forall|index|` ensures into the proof context so the
// disjoint triggers (`post1_self_@[index]` vs `post2_self_@[index]`)
// both get instantiated.
assert(forall|index: int| 0 <= index < N ==> #[trigger] post1_self_@[index] == 0);
assert(forall|index: int| 0 <= index < N ==> #[trigger] post2_self_@[index] == 0);

// `wf()` gives `seq@.len() == N` for both views — needed by `=~=`.
assert(post1_self_.wf());
assert(post2_self_.wf());

// Pointwise: both views are 0 on [0, N), hence equal at every index.
assert forall|index: int| 0 <= index < N implies post1_self_@[index] == post2_self_@[index] by {
    assert(post1_self_@[index] == 0);
    assert(post2_self_@[index] == 0);
}

// Sequence extensionality lifts the pointwise equality to `.view()` ==.
assert(post1_self_@ =~= post2_self_@);
